/**
 * @class GlobalEvent
 * @description Typed global event for gl module (`jibo.gl.global`).
 * In addition to subscribing to events, allows a special meta-subscribe
 * event which fires whenever a listener is added and when the last listener
 * is removed.
 * ```
 * jibo.gl.global.help.subscribe();
 * jibo.gl.global.help.on((data) => {
 *    // data is of type asrResult
 *    // the ASR service has finished listening a cloud result
 *    // and all subscribed listeners will be removed
 * });
 * jibo.gl.global.help.onNoListeners(() => {
 *     // there are no other listeners for the global help command.
 * });
 * // When finished with event listening
 * jibo.gl.global.help.removeLastListener();
 * ```
 * @memberof jibo.gl
 */

    /**
     * Subscribes a handler for once no other listeners are subscribed.
     * @method jibo.gl.GlobalEvent#onNoListeners
     * @return {GlobalEvent} this
     */

    /**
     * Emit that we have no subscribed listeners to all handlers.
     * @method jibo.gl.GlobalEvent#emitNoListeners
     */

    /**
     * Subscribes a handler for every time another listener subscribes.
     * @method jibo.gl.GlobalEvent#onAddedListener
     * @return {GlobalEvent} this
     */

    /**
     * Emit that we added a subscriber to the typed event.
     * @method jibo.gl.GlobalEvent#emitAddListener
     */

    /**
     * Subscribes a handler function to this event
     * @method jibo.gl.GlobalEvent#on
     * @return {GlobalEvent} this
     */

    /**
     * Subscribes a handler function to only the next event
     * @method jibo.gl.GlobalEvent#once
     * @return {GlobalEvent} this
     */

    /**
     * Subscribes a handler function to this event
     * @method jibo.gl.GlobalEvent#addListener
     * @return {GlobalEvent} this
     */

    /**
     * Unsubscribes a handler function from this event
     * @method jibo.gl.GlobalEvent#removeListener
     * @param {jibo.gl.GlobalEvent~Handler} handler Handler to unsubscribe.
     * @return {GlobalEvent} this
     */

    /**
     * Unsubscribes all handler functions from this event
     * @method jibo.gl.GlobalEvent#removeAllListeners
     * @return {GlobalEvent} this
     */

    /**
     * Unsubscribes oldest added subscriber
     * @method jibo.gl.GlobalEvent#removeFirstListener
     * @return {GlobalEvent} this
     */

    /**
     * Unsubscribes most recently added subscriber
     * @method jibo.gl.GlobalEvent#removeLastListener
     * @return {GlobalEvent} this
     */